"use client";

import Link from "next/link";
import { Menu, Home, FileText, ClipboardList, User, LogOut } from "lucide-react";

function SidebarItem({
  href,
  icon,
  label,
  active,
}: {
  href: string;
  icon: React.ReactNode;
  label: string;
  active?: boolean;
}) {
  return (
    <Link
      href={href}
      className={[
        "group/item flex items-center gap-3 rounded-xl px-3 py-2 transition",
        "text-white/90 hover:bg-white/15 hover:text-white",
        active ? "bg-white/20 text-white" : "",
      ].join(" ")}
    >
      <span className="grid h-9 w-9 place-items-center rounded-lg bg-white/10">
        {icon}
      </span>

      {/* teks muncul saat sidebar hover */}
      <span
        className={[
          "whitespace-nowrap text-sm font-semibold",
          "opacity-0 -translate-x-2 transition-all duration-200",
          "group-hover/sidebar:opacity-100 group-hover/sidebar:translate-x-0",
        ].join(" ")}
      >
        {label}
      </span>
    </Link>
  );
}

export default function BahanRapatPage() {
  return (
    <div className="min-h-screen bg-zinc-50">
      {/* background bubble bawah kiri/kanan (ikuti dashboard/login) */}
      <div className="pointer-events-none fixed inset-0 overflow-hidden">
        <div className="absolute bottom-[-140px] left-[-220px] h-[520px] w-[520px] rounded-full bg-[#123473]/35 animate-floating" />
        <div className="absolute bottom-[-220px] left-[-70px] h-[420px] w-[420px] rounded-full bg-[#123473]/55 animate-floating-slow" />
        <div className="absolute bottom-[-140px] right-[-220px] h-[520px] w-[520px] rounded-full bg-[#123473]/35 animate-floating" />
        <div className="absolute bottom-[-220px] right-[-70px] h-[420px] w-[420px] rounded-full bg-[#123473]/55 animate-floating-slow" />
      </div>

      <div className="relative flex">
        {/* Sidebar (expand on hover) */}
        <aside
          className={[
            "group/sidebar sticky top-0 h-screen shrink-0",
            "w-[72px] hover:w-[240px]",
            "bg-[#123473] text-white shadow-lg",
            "transition-all duration-300 ease-in-out overflow-hidden",
          ].join(" ")}
        >
          <div className="flex h-14 items-center justify-center border-b border-white/15">
            <Menu className="h-6 w-6" />
          </div>

          <nav className="flex flex-col gap-2 px-3 py-6">
            <SidebarItem href="/dashboard" icon={<Home size={18} />} label="Dashboard" />
            <SidebarItem
              href="/dashboard/bahan-rapat"
              icon={<FileText size={18} />}
              label="Bahan Rapat"
              active
            />
            <SidebarItem
              href="/dashboard/input-usulan"
              icon={<ClipboardList size={18} />}
              label="Input Usulan"
            />
            <SidebarItem href="/dashboard/profile" icon={<User size={18} />} label="Profile" />
          </nav>

          <div className="mt-auto px-3 pb-6">
            <SidebarItem href="/logout" icon={<LogOut size={18} />} label="Logout" />
          </div>
        </aside>

        {/* Content */}
        <main className="flex-1 px-4 py-6 md:px-8">
          <div className="mx-auto max-w-6xl">
            {/* Paper */}
            <div className="rounded-xl bg-white shadow-[0_18px_55px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
              {/* padding paper */}
              <div className="p-8 md:p-12">
                {/* Header line */}
                <div className="flex items-start justify-between">
                  <div className="text-[11px] font-semibold uppercase tracking-wide text-zinc-900">
                    <div>BADAN NARKOTIKA NASIONAL</div>
                    <div>REPUBLIK INDONESIA</div>
                    <div className="mt-2 h-[2px] w-64 bg-zinc-900/60" />
                  </div>

                  <div className="text-center">
                    <div className="text-[12px] font-semibold uppercase tracking-wide text-zinc-900">
                      MATERI RAPAT
                    </div>
                    <div className="mt-1 text-[11px] text-zinc-700">
                      Tanggal XX XXX 2025
                    </div>
                  </div>

                  {/* spacer biar tengah bener */}
                  <div className="w-64" />
                </div>

                {/* Table */}
                <div className="mt-10 overflow-x-auto">
                  <table className="w-full table-fixed border-collapse text-[11px]">
                    <thead>
                      <tr className="bg-zinc-100 text-zinc-800">
                        <Th className="w-[60px]">NO</Th>
                        <Th className="w-[90px]">ESL</Th>
                        <Th>JABATAN</Th>
                        <Th>NAMA/PKT/GOL<br />NRP/NIP</Th>
                        <Th className="w-[120px]">KONDISI</Th>
                        <Th>CALON PENGISI<br />JABATAN</Th>
                        <Th className="w-[140px]">CATATAN</Th>
                        <Th className="w-[90px]">KET</Th>
                      </tr>
                    </thead>

                    <tbody>
                      {Array.from({ length: 3 }).map((_, i) => (
                        <tr key={i} className="text-zinc-800">
                          <Td className="text-center">{i + 1}</Td>
                          <Td />
                          <Td />
                          <Td />
                          <Td />
                          <Td />
                          <Td />
                          <Td />
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>

                {/* Footer */}
                <div className="mt-8 text-[10px] text-zinc-700">
                  <div>Biro SDM Aparatur dan Organisasi</div>
                  <div>Sekretariat Utama BNN 2025</div>
                </div>
              </div>
            </div>

            {/* spacing bawah biar mirip screenshot */}
            <div className="h-10" />
          </div>
        </main>
      </div>
    </div>
  );
}

/* =======================
   helpers for table cells
======================= */
function Th({ children, className = "" }: { children: React.ReactNode; className?: string }) {
  return (
    <th
      className={[
        "border border-zinc-200 px-3 py-3 text-left font-semibold",
        className,
      ].join(" ")}
    >
      {children}
    </th>
  );
}

function Td({ children, className = "" }: { children?: React.ReactNode; className?: string }) {
  return (
    <td
      className={[
        "h-10 border border-zinc-200 px-3 align-middle",
        className,
      ].join(" ")}
    >
      {children}
    </td>
  );
}
